import { memo, useCallback, useEffect, useMemo, useRef, useState } from 'react';
import type { CSSProperties, MouseEvent as ReactMouseEvent, RefObject } from 'react';
import type { TimelineRow } from '@xzdarcy/timeline-engine';
import type { ClipMeta } from '@/tools/video-editor/lib/timeline-data';

interface OverlayEditorProps {
  rows: TimelineRow[];
  meta: Record<string, ClipMeta>;
  currentTime: number;
  playerContainerRef: RefObject<HTMLDivElement | null>;
  trackScaleMap: Record<string, number>;
  compositionWidth: number;
  compositionHeight: number;
  selectedClipId: string | null;
  onSelectClip: (clipId: string | null) => void;
  onOverlayChange: (actionId: string, patch: Partial<ClipMeta>) => void;
}

type DragMode = 'move' | 'resize-nw' | 'resize-ne' | 'resize-sw' | 'resize-se';
type OverlayBounds = { x: number; y: number; width: number; height: number };
type OverlayLayout = { left: number; top: number; width: number; height: number };

const MIN_CLIP_SIZE = 20;

function OverlayEditorComponent({
  rows,
  meta,
  currentTime,
  playerContainerRef,
  trackScaleMap,
  compositionWidth,
  compositionHeight,
  selectedClipId,
  onSelectClip,
  onOverlayChange,
}: OverlayEditorProps) {
  const [layout, setLayout] = useState<OverlayLayout | null>(null);
  const [editingClipId, setEditingClipId] = useState<string | null>(null);
  const [editText, setEditText] = useState('');
  const [dragOverride, setDragOverride] = useState<{ actionId: string; bounds: OverlayBounds } | null>(null);
  const dragState = useRef<{
    mode: DragMode;
    actionId: string;
    startMouseX: number;
    startMouseY: number;
    startBounds: OverlayBounds;
    latestBounds: OverlayBounds;
    hasChanges: boolean;
  } | null>(null);

  const getTrackDefaultBounds = useCallback((trackId: string): OverlayBounds => {
    const trackScale = Math.max(trackScaleMap[trackId] ?? 1, 0.01);
    return {
      x: Math.round(compositionWidth * (1 - trackScale) / 2),
      y: Math.round(compositionHeight * (1 - trackScale) / 2),
      width: Math.round(compositionWidth * trackScale),
      height: Math.round(compositionHeight * trackScale),
    };
  }, [compositionHeight, compositionWidth, trackScaleMap]);

  const getClipBounds = useCallback((clipMeta: ClipMeta, trackId: string): OverlayBounds => {
    if (clipMeta.clipType === 'text') {
      return {
        x: clipMeta.x ?? 0,
        y: clipMeta.y ?? 0,
        width: clipMeta.width ?? 640,
        height: clipMeta.height ?? 180,
      };
    }

    if (
      clipMeta.x !== undefined
      || clipMeta.y !== undefined
      || clipMeta.width !== undefined
      || clipMeta.height !== undefined
    ) {
      return {
        x: clipMeta.x ?? 0,
        y: clipMeta.y ?? 0,
        width: clipMeta.width ?? compositionWidth,
        height: clipMeta.height ?? compositionHeight,
      };
    }

    return getTrackDefaultBounds(trackId);
  }, [compositionHeight, compositionWidth, getTrackDefaultBounds]);

  const activeOverlays = useMemo(() => {
    const overlays: Array<{ actionId: string; track: string; label: string; bounds: OverlayBounds; isText: boolean }> = [];
    for (const row of rows) {
      if (!row.id.startsWith('V')) {
        continue;
      }

      for (const action of row.actions) {
        if (currentTime < action.start || currentTime >= action.end) {
          continue;
        }

        const clipMeta = meta[action.id];
        if (!clipMeta || clipMeta.track !== row.id) {
          continue;
        }

        const hasPositionOverride = clipMeta.clipType === 'text'
          || clipMeta.x !== undefined
          || clipMeta.y !== undefined
          || clipMeta.width !== undefined
          || clipMeta.height !== undefined;
        if (!hasPositionOverride && selectedClipId !== action.id) {
          continue;
        }

        overlays.push({
          actionId: action.id,
          track: row.id,
          label: clipMeta.text?.content || clipMeta.asset || action.id,
          bounds: getClipBounds(clipMeta, row.id),
          isText: clipMeta.clipType === 'text',
        });
      }
    }

    return overlays;
  }, [currentTime, getClipBounds, meta, rows, selectedClipId]);

  const effectiveOverlays = useMemo(() => {
    if (!dragOverride) {
      return activeOverlays;
    }

    return activeOverlays.map((overlay) => (
      overlay.actionId === dragOverride.actionId
        ? { ...overlay, bounds: dragOverride.bounds }
        : overlay
    ));
  }, [activeOverlays, dragOverride]);

  const computeLayout = useCallback((): OverlayLayout | null => {
    const player = playerContainerRef.current;
    if (!player || compositionWidth <= 0 || compositionHeight <= 0) {
      return null;
    }

    const parent = player.offsetParent as HTMLElement | null;
    if (!parent) {
      return null;
    }

    const playerRect = player.getBoundingClientRect();
    const parentRect = parent.getBoundingClientRect();
    const videoAspect = compositionWidth / compositionHeight;
    const containerAspect = playerRect.width / Math.max(1, playerRect.height);
    const videoWidth = containerAspect > videoAspect ? playerRect.height * videoAspect : playerRect.width;
    const videoHeight = containerAspect > videoAspect ? playerRect.height : playerRect.width / videoAspect;

    return {
      left: playerRect.left - parentRect.left + (playerRect.width - videoWidth) / 2,
      top: playerRect.top - parentRect.top + (playerRect.height - videoHeight) / 2,
      width: videoWidth,
      height: videoHeight,
    };
  }, [compositionHeight, compositionWidth, playerContainerRef]);

  useEffect(() => {
    const updateLayout = () => setLayout(computeLayout());

    updateLayout();
    window.addEventListener('resize', updateLayout);
    const player = playerContainerRef.current;
    const observer = typeof ResizeObserver !== 'undefined' && player ? new ResizeObserver(updateLayout) : null;
    if (observer && player) {
      observer.observe(player);
    }

    return () => {
      window.removeEventListener('resize', updateLayout);
      observer?.disconnect();
    };
  }, [computeLayout, playerContainerRef]);

  const commitDragChange = useCallback(() => {
    const state = dragState.current;
    dragState.current = null;
    setDragOverride(null);

    if (!state || !state.hasChanges) {
      return;
    }

    onOverlayChange(state.actionId, state.latestBounds);
  }, [onOverlayChange]);

  useEffect(() => {
    if (!dragState.current) {
      return;
    }

    const onMouseMove = (event: MouseEvent) => {
      const state = dragState.current;
      if (!state) {
        return;
      }

      const deltaX = event.clientX - state.startMouseX;
      const deltaY = event.clientY - state.startMouseY;
      const nextBounds = { ...state.startBounds };

      if (state.mode === 'move') {
        nextBounds.x += deltaX;
        nextBounds.y += deltaY;
      }
      if (state.mode.includes('e')) {
        nextBounds.width = Math.max(MIN_CLIP_SIZE, state.startBounds.width + deltaX);
      }
      if (state.mode.includes('s')) {
        nextBounds.height = Math.max(MIN_CLIP_SIZE, state.startBounds.height + deltaY);
      }
      if (state.mode.includes('w')) {
        nextBounds.x = state.startBounds.x + deltaX;
        nextBounds.width = Math.max(MIN_CLIP_SIZE, state.startBounds.width - deltaX);
      }
      if (state.mode.includes('n')) {
        nextBounds.y = state.startBounds.y + deltaY;
        nextBounds.height = Math.max(MIN_CLIP_SIZE, state.startBounds.height - deltaY);
      }

      state.latestBounds = nextBounds;
      state.hasChanges = true;
      setDragOverride({ actionId: state.actionId, bounds: nextBounds });
    };

    const onMouseUp = () => commitDragChange();

    window.addEventListener('mousemove', onMouseMove);
    window.addEventListener('mouseup', onMouseUp);
    return () => {
      window.removeEventListener('mousemove', onMouseMove);
      window.removeEventListener('mouseup', onMouseUp);
    };
  }, [commitDragChange, dragOverride]);

  const startDrag = useCallback((event: ReactMouseEvent, actionId: string, mode: DragMode, bounds: OverlayBounds) => {
    event.preventDefault();
    event.stopPropagation();
    onSelectClip(actionId);
    dragState.current = {
      mode,
      actionId,
      startMouseX: event.clientX,
      startMouseY: event.clientY,
      startBounds: bounds,
      latestBounds: bounds,
      hasChanges: false,
    };
  }, [onSelectClip]);

  const beginTextEdit = useCallback((actionId: string) => {
    const clipMeta = meta[actionId];
    if (clipMeta?.clipType !== 'text') {
      return;
    }

    setEditingClipId(actionId);
    setEditText(clipMeta.text?.content ?? '');
  }, [meta]);

  const commitText = useCallback(() => {
    if (!editingClipId) {
      return;
    }

    const clipMeta = meta[editingClipId];
    if (clipMeta?.clipType === 'text') {
      onOverlayChange(editingClipId, {
        text: {
          ...(clipMeta.text ?? { content: '' }),
          content: editText,
        },
      });
    }
    setEditingClipId(null);
  }, [editText, editingClipId, meta, onOverlayChange]);

  if (!layout) {
    return null;
  }

  return (
    <div
      className="pointer-events-none absolute"
      style={{ left: layout.left, top: layout.top, width: layout.width, height: layout.height }}
    >
      {effectiveOverlays.map((overlay) => {
        const left = (overlay.bounds.x / compositionWidth) * layout.width;
        const top = (overlay.bounds.y / compositionHeight) * layout.height;
        const width = (overlay.bounds.width / compositionWidth) * layout.width;
        const height = (overlay.bounds.height / compositionHeight) * layout.height;
        const style: CSSProperties = { left, top, width, height };
        const isSelected = selectedClipId === overlay.actionId;

        return (
          <div
            key={overlay.actionId}
            data-overlay-hit="true"
            className="absolute pointer-events-auto"
            style={style}
          >
            {editingClipId === overlay.actionId && overlay.isText ? (
              <textarea
                data-inline-text-editor="true"
                className="h-full w-full resize-none rounded border border-sky-400 bg-black/80 p-2 text-sm text-white outline-none"
                value={editText}
                onChange={(event) => setEditText(event.target.value)}
                onBlur={commitText}
                onKeyDown={(event) => {
                  if ((event.metaKey || event.ctrlKey) && event.key === 'Enter') {
                    commitText();
                  }
                }}

import type { RefObject } from 'react';
import { forwardRef, useEffect, useImperativeHandle, useMemo, useRef, useState } from 'react';
import { Pause, Play, SkipBack } from 'lucide-react';
import { Player, type PlayerRef } from '@remotion/player';
import { Button } from '@/shared/components/ui/button';
import { TimelineRenderer } from '@/tools/video-editor/compositions/TimelineRenderer';
import { getTimelineDurationInFrames, parseResolution } from '@/tools/video-editor/lib/config-utils';
import type { ResolvedTimelineConfig } from '@/tools/video-editor/types';

export interface PreviewHandle {
  seek: (time: number) => void;
  play: () => void;
  pause: () => void;
  togglePlayPause: () => void;
  readonly isPlaying: boolean;
}

interface RemotionPreviewProps {
  config: ResolvedTimelineConfig;
  onTimeUpdate: (time: number) => void;
  playerContainerRef: RefObject<HTMLDivElement | null>;
  compact?: boolean;
}

export const RemotionPreview = forwardRef<PreviewHandle, RemotionPreviewProps>(function RemotionPreview(
  { config, onTimeUpdate, playerContainerRef, compact = false },
  ref,
) {
  const playerRef = useRef<PlayerRef>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const inputProps = useMemo(() => ({ config }), [config]);
  const metadata = useMemo(() => {
    const fps = config.output.fps;
    const { width, height } = parseResolution(config.output.resolution);

    return {
      fps,
      durationInFrames: getTimelineDurationInFrames(config, fps),
      compositionWidth: Math.max(1, width),
      compositionHeight: Math.max(1, height),
    };
  }, [config]);

  useEffect(() => {
    const player = playerRef.current;
    if (!player) {
      return;
    }

    const onFrameUpdate = (event: { detail: { frame: number } }) => {
      onTimeUpdate(event.detail.frame / metadata.fps);
    };
    const onPlay = () => setIsPlaying(true);
    const onPause = () => setIsPlaying(false);

    player.addEventListener('frameupdate', onFrameUpdate);
    player.addEventListener('play', onPlay);
    player.addEventListener('pause', onPause);

    return () => {
      player.removeEventListener('frameupdate', onFrameUpdate);
      player.removeEventListener('play', onPlay);
      player.removeEventListener('pause', onPause);
    };
  }, [metadata.fps, onTimeUpdate]);

  useImperativeHandle(ref, () => ({
    seek(time: number) {
      playerRef.current?.seekTo(Math.max(0, Math.round(time * metadata.fps)));
    },
    play() {
      playerRef.current?.play();
    },
    pause() {
      playerRef.current?.pause();
    },
    togglePlayPause() {
      playerRef.current?.toggle();
    },
    get isPlaying() {
      return playerRef.current?.isPlaying() ?? isPlaying;
    },
  }), [isPlaying, metadata.fps]);

  return (
    <div
      ref={playerContainerRef}
      className="relative flex h-full min-h-[220px] w-full items-center justify-center overflow-hidden rounded-xl bg-background"
    >
      <Player
        ref={playerRef}
        component={TimelineRenderer}
        inputProps={inputProps}
        durationInFrames={metadata.durationInFrames}
        fps={metadata.fps}
        compositionWidth={metadata.compositionWidth}
        compositionHeight={metadata.compositionHeight}
        controls={false}
        clickToPlay={false}
        doubleClickToFullscreen={false}
        spaceKeyToPlayOrPause={false}
        showVolumeControls={false}
        style={{ width: '100%', height: '100%' }}
      />
      <div className="pointer-events-none absolute inset-x-0 bottom-0 flex items-center justify-center gap-2 bg-gradient-to-t from-black/60 to-transparent px-3 py-3">
        <Button
          type="button"
          variant="outline"
          size="icon"
          className="pointer-events-auto h-8 w-8 rounded-full border-white/20 bg-black/40 text-white hover:bg-black/60"
          onClick={() => playerRef.current?.seekTo(0)}
          title="Jump to beginning"
        >
          <SkipBack className="h-4 w-4" />
        </Button>
        <Button
          type="button"
          variant="outline"
          size="icon"
          className="pointer-events-auto h-10 w-10 rounded-full border-white/20 bg-black/40 text-white hover:bg-black/60"
          onClick={() => playerRef.current?.toggle()}
          title={isPlaying ? 'Pause' : 'Play'}
        >
          {isPlaying ? <Pause className="h-4 w-4" /> : <Play className="h-4 w-4 fill-current" />}
        </Button>
        {!compact && (
          <div className="pointer-events-none rounded-full bg-background/70 px-2 py-1 text-[10px] uppercase tracking-[0.18em] text-muted-foreground">
            {config.output.resolution}
          </div>
        )}
      </div>
    </div>
  );
});

import { useCallback, useEffect, useLayoutEffect, useMemo, useRef, useState } from 'react';
import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query';
import type { TimelineRow } from '@xzdarcy/timeline-engine';
import { getTrackById } from '@/tools/video-editor/lib/editor-utils';
import { buildTrackClipOrder } from '@/tools/video-editor/lib/coordinate-utils';
import { getConfigSignature, parseResolution } from '@/tools/video-editor/lib/config-utils';
import { serializeForDisk } from '@/tools/video-editor/lib/serialize';
import {
  buildTimelineData,
  configToRows,
  preserveUploadingClips,
  rowsToConfig,
  loadTimelineJsonFromProvider,
  type ClipMeta,
  type ClipOrderMap,
  type TimelineData,
} from '@/tools/video-editor/lib/timeline-data';
import { useEditorSettings } from '@/tools/video-editor/settings/useEditorSettings';
import { assetRegistryQueryKey, timelineQueryKey } from '@/tools/video-editor/hooks/useTimeline';
import { useVideoEditorRuntime } from '@/tools/video-editor/contexts/DataProviderContext';
import type { AssetRegistryEntry, TimelineConfig, TrackDefinition } from '@/tools/video-editor/types';

export type SaveStatus = 'saved' | 'saving' | 'dirty' | 'error';
export type RenderStatus = 'idle' | 'rendering' | 'done' | 'error';

export type ClipTab = 'effects' | 'timing' | 'position' | 'audio' | 'text';

export interface EditorPreferences {
  scaleWidth: number;
  activeClipTab: ClipTab;
  assetPanel: {
    showAll: boolean;
    showHidden: boolean;
    hidden: string[];
  };
}

const defaultPreferences: EditorPreferences = {
  scaleWidth: 160,
  activeClipTab: 'effects',
  assetPanel: {
    showAll: false,
    showHidden: false,
    hidden: [],
  },
};

export function shouldAcceptPolledData(
  editSeq: number,
  savedSeq: number,
  polledSig: string,
  lastSavedSig: string,
): boolean {
  if (savedSeq < editSeq) {
    return false;
  }

  return polledSig !== lastSavedSig;
}

export interface ActionDragState {
  rowId: string;
  initialStart: number;
  initialEnd: number;
  latestStart: number;
  latestEnd: number;
}

export interface UseTimelineDataResult {
  data: TimelineData | null;
  resolvedConfig: TimelineData['resolvedConfig'] | null;
  selectedClipId: string | null;
  selectedTrackId: string | null;
  selectedClip: TimelineData['resolvedConfig']['clips'][number] | null;
  selectedTrack: TrackDefinition | null;
  selectedClipHasPredecessor: boolean;
  compositionSize: { width: number; height: number };
  trackScaleMap: Record<string, number>;
  saveStatus: SaveStatus;
  renderStatus: RenderStatus;
  renderLog: string;
  renderDirty: boolean;
  renderProgress: { current: number; total: number; percent: number; phase: string } | null;
  scale: number;
  scaleWidth: number;
  isLoading: boolean;
  dataRef: React.MutableRefObject<TimelineData | null>;
  crossTrackActive: React.MutableRefObject<boolean>;
  actionDragStateRef: React.MutableRefObject<Record<string, ActionDragState>>;
  resizeStartRef: React.MutableRefObject<Record<string, { start: number; from: number }>>;
  preferences: EditorPreferences;
  setSelectedClipId: React.Dispatch<React.SetStateAction<string | null>>;
  setSelectedTrackId: React.Dispatch<React.SetStateAction<string | null>>;
  setRenderStatus: React.Dispatch<React.SetStateAction<RenderStatus>>;
  setRenderLog: React.Dispatch<React.SetStateAction<string>>;
  setRenderDirty: React.Dispatch<React.SetStateAction<boolean>>;
  setScaleWidth: (updater: number | ((value: number) => number)) => void;
  setActiveClipTab: (tab: ClipTab) => void;
  setAssetPanelState: (patch: Partial<EditorPreferences['assetPanel']>) => void;
  applyTimelineEdit: (
    nextRows: TimelineRow[],
    metaUpdates?: Record<string, Partial<ClipMeta>>,
    metaDeletes?: string[],
    clipOrderOverride?: ClipOrderMap,
    options?: { save?: boolean },
  ) => void;
  applyResolvedConfigEdit: (
    nextResolvedConfig: TimelineData['resolvedConfig'],
    options?: { selectedClipId?: string | null; selectedTrackId?: string | null },
  ) => void;
  patchRegistry: (assetId: string, entry: AssetRegistryEntry, src?: string) => void;
  registerAsset: (assetId: string, entry: AssetRegistryEntry) => Promise<void>;
  queryClient: ReturnType<typeof useQueryClient>;
  uploadAsset: (file: File) => Promise<{ assetId: string; entry: AssetRegistryEntry }>;
  uploadFiles: (files: File[]) => Promise<void>;
  invalidateAssetRegistry: () => Promise<void>;
  reloadFromServer: () => Promise<void>;
  startRender: () => Promise<void>;
}

function buildDataFromCurrentRegistry(
  config: TimelineConfig,
  current: TimelineData,
): TimelineData {
  const rowData = configToRows(config);
  const resolvedConfig = {
    output: { ...config.output },
    tracks: config.tracks ?? [],
    clips: config.clips.map((clip) => ({
      ...clip,
      assetEntry: clip.asset ? current.resolvedConfig.registry[clip.asset] : undefined,
    })),
    registry: { ...current.resolvedConfig.registry },
  };

  return {
    config,
    registry: { ...current.registry },
    resolvedConfig,
    rows: rowData.rows,
    meta: rowData.meta,
    effects: rowData.effects,
    assetMap: Object.fromEntries(
      Object.entries(current.registry.assets ?? {}).map(([assetId, entry]) => [assetId, entry.file]),
    ),
    output: { ...config.output },
    tracks: config.tracks ?? [],
    clipOrder: rowData.clipOrder,
    signature: getConfigSignature(resolvedConfig),
  };
}

export function useTimelineData(): UseTimelineDataResult {
  const queryClient = useQueryClient();
  const { provider, timelineId, userId } = useVideoEditorRuntime();
  const saveTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
  const lastSavedSignature = useRef('');
  const editSeqRef = useRef(0);
  const savedSeqRef = useRef(0);
  const dataRef = useRef<TimelineData | null>(null);
  const resizeStartRef = useRef<Record<string, { start: number; from: number }>>({});
  const crossTrackActive = useRef(false);
  const actionDragStateRef = useRef<Record<string, ActionDragState>>({});

  const [data, setData] = useState<TimelineData | null>(null);
  const [selectedClipId, setSelectedClipId] = useState<string | null>(null);
  const [selectedTrackId, setSelectedTrackId] = useState<string | null>(null);
  const [saveStatus, setSaveStatus] = useState<SaveStatus>('saved');
  const [renderStatus, setRenderStatus] = useState<RenderStatus>('idle');
  const [renderLog, setRenderLog] = useState('');
  const [renderDirty, setRenderDirty] = useState(false);
  const [renderProgress, setRenderProgress] = useState<{ current: number; total: number; percent: number; phase: string } | null>(null);
  const [preferences, setPreferences] = useEditorSettings<EditorPreferences>(`video-editor:preferences:${timelineId}`, defaultPreferences);
  const selectedClipIdRef = useRef<string | null>(selectedClipId);
  const selectedTrackIdRef = useRef<string | null>(selectedTrackId);

  const scale = 5;
  const scaleWidth = preferences.scaleWidth;

  useLayoutEffect(() => {
    dataRef.current = data;
    selectedClipIdRef.current = selectedClipId;
    selectedTrackIdRef.current = selectedTrackId;
  }, [data, selectedClipId, selectedTrackId]);

  const timelineQuery = useQuery({
    queryKey: timelineQueryKey(timelineId),
    enabled: Boolean(timelineId),
    queryFn: () => loadTimelineJsonFromProvider(provider, timelineId),
    refetchInterval: 2000,
  });

  const assetRegistryQuery = useQuery({
    queryKey: assetRegistryQueryKey(timelineId),
    enabled: Boolean(timelineId),
    queryFn: () => provider.loadAssetRegistry(timelineId),
    refetchInterval: 2000,
  });

  const saveMutation = useMutation({
    mutationFn: (config: TimelineConfig) => provider.saveTimeline(timelineId, config),
    onError: () => {
      setSaveStatus('error');
      const current = dataRef.current;
      if (current) {
        scheduleSave(current, { preserveStatus: true });
      }
    },
  });

  const materializeData = useCallback((
    current: TimelineData,
    rows: TimelineRow[],
    meta: Record<string, ClipMeta>,
    clipOrder: ClipOrderMap,
  ): TimelineData => {
    const config = rowsToConfig(rows, meta, current.output, clipOrder, current.tracks, current.config.customEffects);
    let result = buildDataFromCurrentRegistry(config, current);
    result = preserveUploadingClips({ ...current, rows, meta } as TimelineData, result);
    return result;
  }, []);

  const saveTimeline = useCallback(async (nextData: TimelineData, seq: number) => {
    setSaveStatus('saving');
    await saveMutation.mutateAsync(nextData.config, {
      onSuccess: () => {
        if (seq > savedSeqRef.current) {
          savedSeqRef.current = seq;
          lastSavedSignature.current = nextData.signature;
        }

        setSaveStatus(seq >= editSeqRef.current ? 'saved' : 'dirty');
        setRenderDirty(true);
      },
    });
  }, [saveMutation]);

  const scheduleSave = useCallback((nextData: TimelineData, options?: { preserveStatus?: boolean }) => {
    if (!options?.preserveStatus) {
      setSaveStatus('dirty');
    }
    if (saveTimer.current) {
      clearTimeout(saveTimer.current);
    }

    saveTimer.current = setTimeout(() => {
      saveTimer.current = null;
      const seq = editSeqRef.current;
      void saveTimeline(nextData, seq);
    }, 500);
  }, [saveTimeline]);

  const commitData = useCallback((
    nextData: TimelineData,
    options?: {
      save?: boolean;
      selectedClipId?: string | null;
      selectedTrackId?: string | null;
      updateLastSavedSignature?: boolean;
    },

import { useEffect, useMemo, useState } from 'react';
import { Clapperboard, Pencil, Plus, Trash2 } from 'lucide-react';
import { useNavigate, useSearchParams } from 'react-router-dom';
import { Button } from '@/shared/components/ui/button';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/shared/components/ui/card';
import { cn } from '@/shared/components/ui/contracts/cn';
import { Input } from '@/shared/components/ui/input';
import { Skeleton } from '@/shared/components/ui/skeleton';
import { useAuth } from '@/shared/contexts/AuthContext';
import { useProjectSelectionContext } from '@/shared/contexts/ProjectContext';
import { useToolSettings } from '@/shared/hooks/settings/useToolSettings';
