export function useTimelineEditing({
  dataRef,
  resolvedConfig,
  data,
  selectedClipId,
  selectedTrackId,
  selectedTrack,
  currentTime,
  scale,
  scaleWidth,
  crossTrackActive,
  actionDragStateRef,
  resizeStartRef,
  setSelectedClipId,
  setSelectedTrackId,
  applyTimelineEdit,
  applyResolvedConfigEdit,
  patchRegistry,
  registerAsset,
  uploadAsset,
  invalidateAssetRegistry,
  resolveAssetUrl,
}: UseTimelineEditingArgs): UseTimelineEditingResult {
  const currentTimeRef = useRef(currentTime);
  const timelineDomCacheRef = useRef<{
    wrapper: HTMLDivElement | null;
    editArea: HTMLElement | null;
    grid: HTMLElement | null;
  }>({
    wrapper: null,
    editArea: null,
    grid: null,
  });
  const dragPreviewFrameRef = useRef<number | null>(null);
  const latestDragPreviewRef = useRef<{
    wrapper: HTMLDivElement;
    time: number;
    rowRect: { top: number; height: number };
    trackName: string;
    wrapperRect: DOMRect;
    pixelsPerSecond: number;
  } | null>(null);
  const dropIndicatorRef = useRef<{
    root: HTMLDivElement;
    row: HTMLDivElement;
    line: HTMLDivElement;
    ghost: HTMLDivElement;
    ghostLabel: HTMLSpanElement;
    label: HTMLDivElement;
  } | null>(null);

  useLayoutEffect(() => {
