                  draggable
                  onDragStart={(event) => {
                    event.dataTransfer.setData('asset-key', assetKey);
                    event.dataTransfer.setData('asset-kind', kind);
                  }}
                >
                  <div className="flex h-8 w-8 items-center justify-center rounded bg-muted text-muted-foreground">
                    {icon}
