                      setPanelState({ hidden: nextHidden });
                    }}
                  >
                    {isHidden ? 'Show' : 'Hide'}
                  </Button>
                </div>
              );
            })}
            {visibleAssets.length === 0 && (
              <div className="rounded-md border border-dashed border-border p-4 text-center text-xs text-muted-foreground">
