 45	    const player = playerRef.current;
 46	    if (!player) {
 47	      return;
 48	    }
 49	
 50	    const onFrameUpdate = (event: { detail: { frame: number } }) => {
 51	      onTimeUpdate(event.detail.frame / metadata.fps);
 52	    };
 53	    const onPlay = () => setIsPlaying(true);
 54	    const onPause = () => setIsPlaying(false);
 55	
