 57	    player.addEventListener('play', onPlay);
 58	    player.addEventListener('pause', onPause);
 59	
 60	    return () => {
 61	      player.removeEventListener('frameupdate', onFrameUpdate);
 62	      player.removeEventListener('play', onPlay);
