    if (nextTimelineId) {
      void update('project', { lastTimelineId: nextTimelineId });
      setSearchParams({ timeline: nextTimelineId }, { replace: true });
      return;
    }

    if (creatingRef.current || timelines.createTimeline.isPending) {
